var e=[{id:`L2_1`,type:`dialog`,speaker:`SIXTH_NPC_NULL_NULL`,text:{KOREA:`<color=#ff3636>크워어어───!!</color>`,JPN:`<color=#ff3636>グオオオ───！！</color>`,ENG:`<color=#ff3636>GRRRRRRAAAAH───!!</color>`,TWN:`<color=#ff3636>轟隆隆───!!</color>`},stage:{bg:`COUNTERSIDE_RED_ADF`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}},sfx:`FX_COMBAT_ALL_HIT_ROCK_BIG_02`},{id:`L4_1`,type:`dialog`,speaker:`KYLE_DELTA_NULL_NULL`,text:{KOREA:`대령님이…… 저 괴물을 압도하고 있어……`,JPN:`大佐が……あの化け物を圧倒している……`,ENG:`The Colonel is pushing back the monster...`,TWN:`上校……壓制住那個怪物……`},stage:{bg:`COUNTERSIDE_RED_ADF`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`KYLE_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L5_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`정말…… 농담이 아니라 진짜 근육 바보였잖아……?`,JPN:`本当に……冗談じゃなくて、本物の脳筋だったの……？`,ENG:`Wow, it’s not a joke. He really is a muscle-bound idiot...`,TWN:`我……不是在作夢，真的是肌肉傻瓜……？`},stage:{bg:`COUNTERSIDE_RED_ADF`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`KYLE_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`JAINA_DELTA_NULL_NULL`,text:{KOREA:`제가 정말…… 저런 남자랑 싸웠다고요?`,JPN:`私は本当に……あんな男と戦ったのですか？`,ENG:`I actually... fought that guy?`,TWN:`我真的……和那個男人交手過嗎？`},stage:{bg:`COUNTERSIDE_RED_ADF`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_LAUGH`}}}},{id:`L9_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`……조금 늦었어, 꼬마.`,JPN:`……遅かったじゃないか、チビ。`,ENG:`You’re late, kid.`,TWN:`……小鬼，你晚了。`},stage:{bg:`COUNTERSIDE_RED_ADF`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`하지만 너무 늦지는 않았군.`,JPN:`だが、間に合ったようだな。`,ENG:`But not too late.`,TWN:`不過不算太晚。`},stage:{bg:`COUNTERSIDE_RED_ADF`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`보고 있나, 도미닉?`,JPN:`見ているか？　ドミニーク。`,ENG:`Are you looking at this, Dominic?`,TWN:` 多明尼克，你有看到嗎？`},stage:{bg:`COUNTERSIDE_RED_ADF`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`저 꼬마에게 미래를 걸기로 한 내 도박이…… 제법 성공한 모양인데?`,JPN:`あのチビに未来をかけることにした私の賭けは……どうやら勝ったようだ。`,ENG:`My bet on this boy... is finally paying off.`,TWN:`我賭那小鬼的未來……似乎沒有賭錯？`},stage:{bg:`COUNTERSIDE_RED_ADF`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`됐어! 놈의 왼팔을 날려버렸다!`,JPN:`よし！　奴の左腕を吹き飛ばした！`,ENG:`Okay, I got its left arm!`,TWN:`成功了！那傢伙的左臂斷了！`},stage:{bg:`MAINSTREAM_805`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}},sfx:`FX_CUTSCEN_HOWLING_03`},{id:`L16_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`지금이야! 아가씨!`,JPN:`今だ！　お嬢ちゃん！`,ENG:`Move in now, lady!`,TWN:`就是現在！傭兵小姐！`},stage:{bg:`MAINSTREAM_805`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`말하지 않아도 알고 있어!`,JPN:`言われなくてもわかってる！`,ENG:`You don’t have to tell me, I know!`,TWN:`不用你說我也知道！`},stage:{bg:`MAINSTREAM_805`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`내게 맡겨, 한 번에 끝내겠어!`,JPN:`私に任せて、一気に終わらせる！`,ENG:`I’ll finish it with one shot!`,TWN:`交給我，一刀就讓你斃命！`},stage:{bg:`MAINSTREAM_805`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`보기보다 화끈한데?! 혹시 입대할 생각 없나?`,JPN:`意外と豪快な性格じゃないか！　うちに入隊するつもりはないか？`,ENG:`Hey, you’re pretty feisty! Are you interested in joining the army?`,TWN:`沒想到你是小辣椒？！有考慮要加入軍隊嗎？`},stage:{bg:`MAINSTREAM_805`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`됐거든! 직장생활만 해도 힘들어!`,JPN:`やめておく！　今の職場だけでも精一杯なの！`,ENG:`No thanks! Office life is tough enough for me!`,TWN:`免了！光是當個上班族就已經夠累人了！`},stage:{bg:`MAINSTREAM_805`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`이거나…… 처먹어라!!`,JPN:`これでも……食らえ！！`,ENG:`Now... take this!`,TWN:`受死……吧！！`},stage:{bg:`MAINSTREAM_805`,bgm:`THEMA_STORM`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};